package main

import (
	"fmt"
	"math"
)

// solve calculates the number of integers in the range [1, n] with exactly k popcount-depth.
func solve(n int64, k int64) int64 {
	if k == 0 {
		return 0
	}

	// Precompute the popcount-depth for all numbers up to a certain limit
	// We use BFS to compute the popcount-depth for all numbers up to n
	// Since n can be up to 1e15, we need an efficient way to compute this

	// We use a breadth-first search approach to compute the popcount-depth for all numbers
	// Starting from 1, we compute the popcount-depth for each number
	// We use a queue to process numbers in order of their popcount-depth

	// We also use a map to store the popcount-depth for each number
	// To handle large numbers, we use a map with keys as integers and values as their popcount-depth

	// Initialize the queue with 1, which has a popcount-depth of 1
	queue := []int64{1}
	depthMap := make(map[int64]int64)
	depthMap[1] = 1

	// Process the queue
	for len(queue) > 0 {
		current := queue[0]
		queue = queue[1:]

		// Get the popcount of the current number
		popcount := popcount(current)

		// If the popcount is 1, we have reached the end of the sequence
		if popcount == 1 {
			depthMap[current] = depthMap[current] + 1
		} else {
			// Compute the next number in the sequence
			next := popcount
			if depthMap[next] == 0 {
				depthMap[next] = depthMap[current] + 1
				queue = append(queue, next)
			}
		}
	}

	// Count the numbers in [1, n] with exactly k popcount-depth
	count := 0
	for i := int64(1); i <= n; i++ {
		if depthMap[i] == k {
			count++
		}
	}

	return int64(count)
}

// popcount returns the number of 1s in the binary representation of x
func popcount(x int64) int64 {
	count := 0
	for x > 0 {
		count += x & 1
		x >>= 1
	}
	return int64(count)
}
